import React, { useCallback, useEffect, useMemo, useState } from 'react'
import { productService } from '../../services/api'
import { showToast } from '../../utils/toast'
import PondChartCard from '../../components/charts/PondChartCard'
import '../../styles/product-management.css'

const emptyCategoryForm = {
  categoryName: '',
  note: '',
}

const emptyProductForm = {
  categoryId: '',
  categoryName: '',
  productName: '',
  unit: '',
  supplier: '',
  unitPrice: '',
  note: '',
}

const emptyOverview = {
  totalCategories: 0,
  totalProducts: 0,
  totalSuppliers: 0,
  topCategory: null,
  categoryStats: [],
  supplierStats: [],
  topProducts: [],
}

const PAGE_SIZE = 8

const formatDateTime = (value) => {
  if (!value) return '-'
  const date = new Date(value)
  if (Number.isNaN(date.getTime())) return value

  return new Intl.DateTimeFormat('vi-VN', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'Asia/Ho_Chi_Minh',
  }).format(date)
}

const formatCurrency = (value) => {
  const amount = Number(value || 0)
  return `${amount.toLocaleString('vi-VN')} đ`
}

const normalizeText = (value) => String(value || '').trim().toLowerCase()

const createPalette = (baseColors) => (index) => baseColors[index % baseColors.length]

const pickCategoryColor = createPalette([
  '#3b82f6',
  '#10b981',
  '#f59e0b',
  '#8b5cf6',
  '#06b6d4',
  '#ef4444',
])

const pickSupplierColor = createPalette([
  '#0ea5e9',
  '#22c55e',
  '#f97316',
  '#a855f7',
  '#f43f5e',
  '#64748b',
])

const pickProductColor = createPalette([
  '#0284c7',
  '#0f766e',
  '#f59e0b',
  '#7c3aed',
  '#16a34a',
  '#ef4444',
])

const ProductManagementPage = ({ roleLabel = 'Owner' }) => {
  const [overview, setOverview] = useState(emptyOverview)
  const [categories, setCategories] = useState([])
  const [products, setProducts] = useState([])
  const [loading, setLoading] = useState(true)

  const [savingCategory, setSavingCategory] = useState(false)
  const [savingProduct, setSavingProduct] = useState(false)

  const [activeTab, setActiveTab] = useState('products')

  const [categorySearch, setCategorySearch] = useState('')
  const [categoryFilter, setCategoryFilter] = useState('ALL')

  const [productSearch, setProductSearch] = useState('')
  const [supplierSearch, setSupplierSearch] = useState('')
  const [productCategoryFilter, setProductCategoryFilter] = useState('ALL')

  const [categoryPage, setCategoryPage] = useState(1)
  const [productPage, setProductPage] = useState(1)

  const [showCategoryModal, setShowCategoryModal] = useState(false)
  const [showProductModal, setShowProductModal] = useState(false)

  const [categoryForm, setCategoryForm] = useState(emptyCategoryForm)
  const [productForm, setProductForm] = useState(emptyProductForm)

  const [editingCategoryId, setEditingCategoryId] = useState(null)
  const [editingProductId, setEditingProductId] = useState(null)

  const [detailType, setDetailType] = useState('')
  const [detailData, setDetailData] = useState(null)
  const [detailLoading, setDetailLoading] = useState(false)
  const [showDetailModal, setShowDetailModal] = useState(false)

  const fetchData = useCallback(async () => {
    try {
      setLoading(true)

      const [overviewRes, categoriesRes, productsRes] = await Promise.all([
        productService.getProductOverview(),
        productService.getProductCategories(),
        productService.getProducts(),
      ])

      setOverview(overviewRes?.data?.data || emptyOverview)
      setCategories(categoriesRes?.data?.data || [])
      setProducts(productsRes?.data?.data || [])
    } catch (err) {
      showToast({
        title: err?.response?.data?.message || 'Không tải được dữ liệu sản phẩm',
        type: 'error',
      })
    } finally {
      setLoading(false)
    }
  }, [])

  useEffect(() => {
    fetchData()
  }, [fetchData])

  const totalSuppliers = useMemo(() => {
    const suppliers = new Set(
      products
        .map((item) => String(item.supplier || '').trim())
        .filter(Boolean)
    )

    return suppliers.size
  }, [products])

  const filteredCategories = useMemo(() => {
    return categories.filter((item) => {
      const matchesSearch =
        !categorySearch ||
        normalizeText(item.category_name).includes(normalizeText(categorySearch))

      const count = Number(item.product_count || 0)

      const matchesFilter =
        categoryFilter === 'ALL'
          ? true
          : categoryFilter === 'HAS_PRODUCTS'
            ? count > 0
            : count === 0

      return matchesSearch && matchesFilter
    })
  }, [categories, categorySearch, categoryFilter])

  const filteredProducts = useMemo(() => {
    return products.filter((item) => {
      const matchesProduct =
        !productSearch ||
        normalizeText(item.product_name).includes(normalizeText(productSearch))

      const matchesSupplier =
        !supplierSearch ||
        normalizeText(item.supplier).includes(normalizeText(supplierSearch))

      const matchesCategory =
        productCategoryFilter === 'ALL' ||
        String(item.category_id) === String(productCategoryFilter)

      return matchesProduct && matchesSupplier && matchesCategory
    })
  }, [products, productSearch, supplierSearch, productCategoryFilter])

  const categoryTotalPages = Math.max(
    1,
    Math.ceil(filteredCategories.length / PAGE_SIZE)
  )

  const productTotalPages = Math.max(
    1,
    Math.ceil(filteredProducts.length / PAGE_SIZE)
  )

  const categoryPageSafe = Math.min(categoryPage, categoryTotalPages)
  const productPageSafe = Math.min(productPage, productTotalPages)

  const paginatedCategories = filteredCategories.slice(
    (categoryPageSafe - 1) * PAGE_SIZE,
    categoryPageSafe * PAGE_SIZE
  )

  const paginatedProducts = filteredProducts.slice(
    (productPageSafe - 1) * PAGE_SIZE,
    productPageSafe * PAGE_SIZE
  )

  const categoryChartData = useMemo(() => {
    return (overview.categoryStats || []).map((item, index) => ({
      label: item.label,
      value: Number(item.value || 0),
      color: pickCategoryColor(index),
    }))
  }, [overview.categoryStats])

  const supplierChartData = useMemo(() => {
    return (overview.supplierStats || []).map((item, index) => ({
      label: item.label,
      value: Number(item.value || 0),
      color: pickSupplierColor(index),
    }))
  }, [overview.supplierStats])

  const productChartData = useMemo(() => {
    return (overview.topProducts || []).map((item, index) => ({
      label: item.label,
      value: Number(item.value || 0),
      color: pickProductColor(index),
    }))
  }, [overview.topProducts])

  if (loading) {
    return (
      <div className="dashboard product-management_page">
        <div className="flex-center" style={{ height: '100vh' }}>
          <div className="spinner"></div>
        </div>
      </div>
    )
  }

  return (
    <div className="dashboard product-management_page">
      <div className="product-management_header">
        <div>
          <h1>Quản lý sản phẩm</h1>
          <p>Quản lý danh mục và sản phẩm sử dụng trong nuôi tôm</p>
        </div>

        <div className="product-management_header-actions">
          <button className="btn btn-primary">
            + Thêm sản phẩm
          </button>

          <button className="btn btn-secondary">
            + Thêm danh mục
          </button>
        </div>
      </div>

      <div className="stats-grid product-management_stats-grid">
        <div className="stats-card stats-card--primary stats-card-row">
          <div className="stats-card-icon">📂</div>

          <div className="stats-card-content">
            <span className="stats-card-label">Tổng danh mục</span>
            <strong className="stats-card-value">
              {overview.totalCategories}
            </strong>
            <span className="stats-card-subtitle">
              Dữ liệu theo trại {roleLabel}
            </span>
          </div>
        </div>

        <div className="stats-card stats-card--success stats-card-row">
          <div className="stats-card-icon">🧪</div>

          <div className="stats-card-content">
            <span className="stats-card-label">Tổng sản phẩm</span>
            <strong className="stats-card-value">
              {overview.totalProducts}
            </strong>
            <span className="stats-card-subtitle">
              Sẵn sàng cho nghiệp vụ khác
            </span>
          </div>
        </div>

        <div className="stats-card stats-card--warning stats-card-row">
          <div className="stats-card-icon">🏷️</div>

          <div className="stats-card-content">
            <span className="stats-card-label">Tổng nhà cung cấp</span>
            <strong className="stats-card-value">
              {totalSuppliers}
            </strong>
            <span className="stats-card-subtitle">
              Từ danh sách hiện có
            </span>
          </div>
        </div>

        <div className="stats-card stats-card--info stats-card-row">
          <div className="stats-card-icon">⭐</div>

          <div className="stats-card-content">
            <span className="stats-card-label">
              Danh mục nhiều sản phẩm nhất
            </span>

            <strong className="stats-card-value">
              {overview.topCategory?.label || '-'}
            </strong>

            <span className="stats-card-subtitle">
              {overview.topCategory
                ? `${overview.topCategory.value} sản phẩm`
                : 'Chưa có dữ liệu'}
            </span>
          </div>
        </div>
      </div>

      <div className="product-management_charts-grid">
        <PondChartCard
          prefix="owner-ponds"
          title="Số lượng sản phẩm theo danh mục"
          type="doughnut"
          data={categoryChartData}
          total={overview.totalProducts}
        />

        <PondChartCard
          prefix="owner-ponds"
          title="Phân bố sản phẩm theo nhà cung cấp"
          type="bar"
          data={supplierChartData}
        />

        <PondChartCard
          prefix="owner-ponds"
          title="Sản phẩm được sử dụng nhiều nhất"
          type="bar"
          data={productChartData}
        />
      </div>
    </div>
  )
}

export default ProductManagementPage
